import React, { useState, useEffect } from 'react';

const ws_url = 'ws://localhost:8001/ws';

function App() {
    const [messages, setMessages] = useState([]);
    const [socket, setSocket] = useState(null);
    const [inputMessage, setInputMessage] = useState(''); // Store user input

    useEffect(() => {
        // Create a WebSocket connection
        const ws = new WebSocket(`${ws_url}/abc-123`);

        ws.onopen = () => {
            console.log('WebSocket connection established');
        };

        ws.onmessage = (event) => {
            const data = JSON.parse(event.data);
            console.log('Received message:', data);

            // Assuming the message contains a "content" field
            if (data.type === 'chunk' && data.content) {
                setMessages(prevMessages => [...prevMessages, { content: data.content, id: Date.now() }]);
            }
        };

        ws.onerror = (error) => {
            console.error('WebSocket error:', error);
        };

        ws.onclose = () => {
            console.log('WebSocket connection closed');
        };

        // Store WebSocket connection in state
        setSocket(ws);

        // Cleanup on component unmount
        return () => {
            if (ws) {
                ws.close();
            }
        };
    }, []);

    // Send a message to the WebSocket server
    const sendMessage = () => {
        if (socket && socket.readyState === WebSocket.OPEN) {
            const message = {
                query: inputMessage,  // Send user input message
                user: "abc-123",      // User ID (can be dynamic or hardcoded)
                conversation_id: "",  // Optional: You can add a conversation ID
            };

            // Send the message in the proper format to the WebSocket
            socket.send(JSON.stringify(message));
            setInputMessage(''); // Clear input after sending
        } else {
            console.error('WebSocket is not open');
        }
    };

    return (
        <div>
            <h1>Chat</h1>
            <ul>
                {messages.map((message, index) => (
                    <li key={index}>{message.content}</li>
                ))}
            </ul>

            {/* Input field for user message */}
            <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}  // Update inputMessage state on change
                placeholder="Type a message..."
            />

            {/* Send the message when the button is clicked */}
            <button onClick={sendMessage}>Send Message</button>
        </div>
    );
}

export default App;
